#!/usr/bin/env python3
"""Deploy updated files with balance recovery system."""
import base64, gzip, os, sys, py_compile
os.chdir('/root/polymarket-5m-bot')
FILES = {
    'bot.py': '',
    'core/execution.py': '',
    'utils/telegram.py': '',
    'scripts/recover_all.py': '',
}

print(f'Deploying to: {os.getcwd()}')
for path, b64data in FILES.items():
    content = gzip.decompress(base64.b64decode(b64data))
    if os.path.exists(path):
        with open(path + '.bak', 'wb') as f:
            f.write(open(path, 'rb').read())
    os.makedirs(os.path.dirname(path) or '.', exist_ok=True)
    with open(path, 'wb') as f:
        f.write(content)
    print(f'  OK: {path} ({len(content)} bytes)')

print()
for path in FILES:
    if path.endswith('.py'):
        try:
            py_compile.compile(path, doraise=True)
            print(f'  Syntax OK: {path}')
        except py_compile.PyCompileError as e:
            print(f'  SYNTAX ERROR: {e}')
            sys.exit(1)

print('\nDone! Run: pm2 restart polymarket-bot')
print('Then: venv/bin/python3 scripts/recover_all.py')
